#include <stdio.h>
#include <stdlib.h>

#define MAX_NODES 100002

typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

Node* adj[MAX_NODES];

void add_edge(int u, int v) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->vertex = v;
    newNode->next = adj[u];
    adj[u] = newNode;
}

void dfs(int node, int parent, int d, int *maxd) {
    if (d > *maxd) {
        *maxd = d;
    }
    Node* current = adj[node];
    while (current != NULL) {
        int v = current->vertex;
        if (v != parent) {
            dfs(v, node, d + 1, maxd);
        }
        current = current->next;
    }
}

int main() {
    int n;
    scanf("%d", &n);

    int depth = 0;

    // Initialize adjacency list
    for (int i = 0; i <= n; i++) {
        adj[i] = NULL;
    }

    // Read edges and build adjacency list
    for (int i = 1; i < n; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        add_edge(u, v);
        add_edge(v, u);
    }

    // Start DFS from node 1
    dfs(1, -1, 0, &depth);

    printf("%d\n", depth);

    // Free the allocated memory
    for (int i = 0; i <= n; i++) {
        Node* current = adj[i];
        while (current != NULL) {
            Node* temp = current;
            current = current->next;
            free(temp);
        }
    }

    return 0;
}

