import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

 class Codechef {

    static List<Integer>[] adj = new ArrayList[100001];

    public static void dfs(int node, int parent, int d, int[] maxd) {
        maxd[0] = Math.max(d, maxd[0]);
        for (int v : adj[node]) {
            if (v != parent) {
                dfs(v, node, d + 1, maxd);
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int depth = 0;

        for (int i = 0; i < adj.length; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 1; i < n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            adj[u].add(v);
            adj[v].add(u);
        }

        int[] maxd = new int[1];
        dfs(1, -1, 0, maxd);
        System.out.println(maxd[0]);
    }
}

