function findTreeHeight(N, edges) {
    // Create adjacency list for the tree
    const tree = Array.from({ length: N + 1 }, () => []);

    // Construct the adjacency list
    for (const [u, v] of edges) {
        tree[u].push(v);
        tree[v].push(u);
    }

    // BFS to find the maximum depth (height) of the tree
    let queue = [1];
    let visited = new Array(N + 1).fill(false);
    let depth = new Array(N + 1).fill(0);
    visited[1] = true;

    while (queue.length > 0) {
        let node = queue.shift();

        for (let neighbor of tree[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                depth[neighbor] = depth[node] + 1;
                queue.push(neighbor);
            }
        }
    }

    // Find the maximum depth value
    let maxHeight = 0;
    for (let i = 1; i <= N; i++) {
        if (depth[i] > maxHeight) {
            maxHeight = depth[i];
        }
    }

    return maxHeight;
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let N = 0;
    let edges = [];

    rl.on('line', (line) => {
        if (N === 0) {
            N = parseInt(line.trim());
        } else {
            const [u, v] = line.trim().split(' ').map(Number);
            edges.push([u, v]);
            if (edges.length === N - 1) {
                rl.close();
            }
        }
    });

    rl.on('close', () => {
        const height = findTreeHeight(N, edges);
        console.log(height);
        process.exit(0);
    });
}

// Run the main function
main();
